        """Adds a job to the scheduler."""
        if job_name in self.jobs:
            raise ValueError(f"Job {job_name} already exists.")

        dependencies = dependencies or []

        # Pre-check for known dependencies existence (assuming other jobs will be added later)
        # This initial check might be insufficient, but we handle unknown deps later during run/validation.

        self.jobs[job_name] = {
            'func': func,
            'deps': set(dependencies),
            'priority': priority
        }

    def _validate_dependencies(self):
        """Validates all dependencies for existence and detects cycles."""
        graph = {}
        node_deps = {} # job -> dependencies

        for name, job in self.jobs.items():
            graph[name] = []
            node_deps[name] = set(job['deps'])

        # Build the adjacency list (Dependency graph: dep -> dependent)
        rev_graph = {name: [] for name in self.jobs}
        for name, job in self.jobs.items():
            for dep in job['deps']:
                if dep not in self.jobs:
                    raise UnknownDependencyError(f"Job '{name}' depends on unknown job '{dep}'.")
                rev_graph[dep].append(name)

