        visited = set()
        recursion_stack = set()

        def is_cyclic_util(node):
            if node in recursion_stack:
                return True  # Cycle detected
            if node in visited:
                return False # Already processed and confirmed acyclic

            visited.add(node)
            recursion_stack.add(node)

            for neighbor in rev_graph[node]:
                # Note: We are building the graph dependency -> dependent, 
                # but for cycle detection in a topological sort context, 
                # we check cycles on the direct dependency relationship.
                # If A depends on B, there is an edge B -> A.
                # Let's check dependencies: For job X, if it depends on Y, we check edge Y -> X.
                if is_cyclic_util(neighbor):
                    return True

            recursion_stack.remove(node)
            return False

