                # and since we validated cycles already, it implies logic failure/dependency issue.
                break # Safety break

            # Select the job with the highest priority (assuming lower number means higher priority, standard convention)
            ready_to_run.sort(key=lambda x: x['priority'])
            job_to_run = ready_to_run[0]
            job_name = job_to_run['name']

            print(f"--- Running job: {job_name} (Priority: {job_to_run['priority']}) ---")

            try:
                func = self.jobs[job_name]['func']
                result = func() # Execute the function associated with the job
                self._results[job_name] = result
                available_jobs.remove(job_name)
