    # Job C depends on A and B. A is high priority (0), B is mid (5).
    scheduler.add_job("JobA", job_a) 
    scheduler.add_job("JobB", job_b)
    scheduler.add_job("JobC", job_c, dependencies=["JobA", "JobB"], priority=10)

    try:
        results = scheduler.run()
        print("\\nExecution Results:", results)

        print(f"Result of JobC: {scheduler.get_result('JobC')}")

    except (CycleError, UnknownDependencyError, RuntimeError) as e:
        print(f"Scheduler Error caught: {e.__class__.__name__}: {e}")
    finally:
        scheduler.reset()
